import os
from github import Github

GITHUB_TOKEN = os.getenv("GITHUB_TOKEN")

g = Github(GITHUB_TOKEN)


def create_or_update_repo(project_type):

    repo_name = "atlas-" + project_type.split()[0].lower()

    user = g.get_user()

    try:
        repo = user.get_repo(repo_name)
        version = "v2"
    except:
        repo = user.create_repo(repo_name)
        version = "v1"

    files = {

        "README.md": f"# {repo_name}\n\nGenerated by Atlas AI\n",

        ".env.example": """
NEXT_PUBLIC_SUPABASE_URL=
NEXT_PUBLIC_SUPABASE_KEY=
STRIPE_SECRET_KEY=
""",

        "frontend/pages/index.js": """
export default function Home() {
  return (
    <div style={{padding:40}}>
      <h1>Atlas Generated App</h1>
      <p>Your AI generated project is ready.</p>
    </div>
  )
}
""",

        "frontend/components/Navbar.js": """
export default function Navbar(){
  return (
    <nav>
      <h2>Atlas App</h2>
    </nav>
  )
}
""",

        "frontend/styles/globals.css": """
body {
  font-family: sans-serif;
  margin: 0;
}
""",

        "backend/server.js": """
const express = require('express')
const app = express()

app.get('/', (req,res)=>{
  res.send('Atlas backend running')
})

app.listen(3001)
""",

        "backend/api/orders.js": """
export default function handler(req,res){
  res.status(200).json({message:"orders endpoint"})
}
""",

        "database/schema.sql": """
CREATE TABLE orders(
 id SERIAL PRIMARY KEY,
 customer_name TEXT,
 product TEXT,
 created_at TIMESTAMP DEFAULT NOW()
);
"""
    }

    for path, content in files.items():

        try:
            existing = repo.get_contents(path)

            repo.update_file(
                existing.path,
                "Atlas automated update",
                content,
                existing.sha
            )

        except:

            repo.create_file(
                path,
                "Atlas automated project build",
                content
            )

    return repo_name, version